const API_URL = "https://api.ivxholding.com";

const headers = {
  apikey: SERVICE_KEY,
  Authorization: `Bearer ${SERVICE_KEY}`,
  "Content-Type": "application/json",
};

async function fetchRecord(table, idColumn, id) {
  const url = `${SUPABASE_URL}/rest/v1/${table}?${idColumn}=eq.${id}&limit=1`;
  try {
    const res = await fetch(url, { headers });
    const status = res.status;
    const body = await res.json();
    const found = Array.isArray(body) && body.length > 0;
    return { table, idColumn, id, http: status, found, record: found ? body[0] : null, raw: body };
  } catch (err) {
    return { table, idColumn, id, http: 0, found: false, error: err.message };
  }
}

async function fetchAll(table, filter) {
  const url = `${SUPABASE_URL}/rest/v1/${table}?${filter}`;
  try {
    const res = await fetch(url, { headers });
    const status = res.status;
    const body = await res.json();
    return { table, filter, http: status, count: Array.isArray(body) ? body.length : 0, records: body };
  } catch (err) {
    return { table, filter, http: 0, count: 0, error: err.message };
  }
}

async function fetchCount(table, filter) {
  const url = `${SUPABASE_URL}/rest/v1/${table}?${filter}&select=*`;
  try {
    const res = await fetch(url, { headers: { ...headers, "Prefer": "count=exact", "Range": "0-0" } });
    const range = res.headers.get("content-range");
    const count = range ? parseInt(range.split("/")[1]) : 0;
    return { table, filter, http: res.status, count };
  } catch (err) {
    return { table, filter, http: 0, count: 0, error: err.message };
