    { key: "member", tables: ["ivx_members", "members"], idCol: "member_id" },
    { key: "member", tables: ["ivx_members", "members"], idCol: "id" },
    // investors
    { key: "investor", tables: ["ivx_investors", "investors"], idCol: "id" },
    { key: "investor", tables: ["ivx_investors", "investors"], idCol: "investor_id" },
