    checks.push({ label: `email1:${tbl}`, fn: () => fetchRecord(tbl, "id", recordIds.email_notification_1) });
    checks.push({ label: `email2:${tbl}`, fn: () => fetchRecord(tbl, "id", recordIds.email_notification_2) });
